Here's a simple illustration. Assume we have a hypothetical class that performs a shadow copy (note: this example uses direct pointer copying for demonstration, which is highly discouraged in actual code due to the reasons previously mentioned, including potential memory management issues):

```cpp
class ShadowCopyExample {
public:
    int* data;

    ShadowCopyExample(int value) {
        data = new int(value);
    }

    // Shadow copy constructor
    ShadowCopyExample(const ShadowCopyExample& other) {
        this->data = other.data; // Both objects now share the same int pointer
    }

    ~ShadowCopyExample() {
        delete data;
    }

    void setValue(int value) {
        *data = value;
    }

    int getValue() const {
        return *data;
    }
